import React, { useState, useEffect } from 'react'
import axios from 'axios'

export default function TelaCaixas() {
  const [caixas, setCaixas] = useState([])
  const [nome, setNome] = useState('')
  const [codigo, setCodigo] = useState('')

  useEffect(() => {
    fetchCaixas()
  }, [])

  async function fetchCaixas() {
    try {
      const { data } = await axios.get('/api/caixas')
      setCaixas(data)
    } catch (err) {
      console.error(err)
    }
  }

  async function handleSubmit(e) {
    e.preventDefault()
    try {
      await axios.post('/api/caixas', {
        nome,
        codigo_barras: codigo
      })
      setNome('')
      setCodigo('')
      fetchCaixas()
    } catch (err) {
      console.error(err)
      alert('Erro ao cadastrar caixa')
    }
  }

  return (
    <div className="max-w-3xl mx-auto py-8 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Gerenciar Caixas</h2>
      <form onSubmit={handleSubmit} className="flex gap-2">
        <input
          className="flex-1 border px-3 py-2"
          placeholder="Nome da Caixa"
          value={nome}
          onChange={e => setNome(e.target.value)}
          required
        />
        <input
          className="w-48 border px-3 py-2"
          placeholder="Código de Barras"
          value={codigo}
          onChange={e => setCodigo(e.target.value)}
          required
        />
        <button
          type="submit"
          className="px-4 py-2 bg-blue-600 text-white rounded"
        >
          Cadastrar
        </button>
      </form>

      <table className="w-full border-collapse">
        <thead>
          <tr className="bg-gray-100">
            <th className="p-2 text-left">ID</th>
            <th className="p-2 text-left">Nome</th>
            <th className="p-2 text-left">Código</th>
          </tr>
        </thead>
        <tbody>
          {caixas.map(c => (
            <tr key={c.id} className="border-t">
              <td className="p-2">{c.id}</td>
              <td className="p-2">{c.nome}</td>
              <td className="p-2">{c.codigo_barras}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
